package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

import static edu.rice.hj.Module0.finish;
import static edu.rice.hj.Module1.async;
import static edu.rice.hj.Module1.doWork;

/**
 * A scorer that works in parallel.
 */
public class IdealParScoring extends AbstractPreallocatedSorting {

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(IdealParScoring::new);
        scoringRunner.start("IdealParScoring", args);
    }

    /**
     * Creates a new IdealParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public IdealParScoring(final int xLength, final int yLength) {
        super(xLength, yLength);
    }

    /**
     * This method should be filled in with a parallel implementation of the Smith-Waterman alignment algorithm that
     * maximizes ideal parallelism.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        final int xLength = getXLength();
        final int yLength = getYLength();
        final int[][] S = getMatrix();

        // Wavefront parallelism: process cells on anti-diagonals in parallel
        // For each anti-diagonal k from 1 to xLength + yLength
        for (int k = 1; k <= xLength + yLength; k++) {
            final int pk = k;
            // All cells (i, j) where i + j = k can be computed in parallel
            finish(() -> {
                for (int i = Math.max(1, pk - yLength); i <= Math.min(xLength, pk - 1); i++) {
                    final int fi = i;
                    final int fj = pk - i;
                    if (fj >= 1 && fj <= yLength) {
                        async(() -> {
                            // Get characters to compare
                            final char XChar = x.charAt(fi - 1);
                            final char YChar = y.charAt(fj - 1);

                            // Compute the three possible scores
                            final int diagScore = S[fi - 1][fj - 1] + getScore(charMap(XChar), charMap(YChar));
                            final int topColScore = S[fi - 1][fj] + getScore(charMap(XChar), 0);
                            final int leftRowScore = S[fi][fj - 1] + getScore(0, charMap(YChar));

                            // Set the maximum score
                            S[fi][fj] = Math.max(diagScore, Math.max(leftRowScore, topColScore));

                            // Track work for abstract metrics
                            doWork(1);
                        });
                    }
                }
            });
        }

        // Return the final alignment score
        return S[xLength][yLength];
    }

}

package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

/**
 * A scorer that allocates memory during computation, so that it may compute the scores for two sequences without
 * requiring O(|X||Y|) memory.
 */
public class SparseParScoring extends AbstractDnaScoring {

    private final int xLength;
    private final int yLength;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(SparseParScoring::new);
        scoringRunner.start("SparseParScoring", args);
    }

    /**
     * Creates a new SparseParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public SparseParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }
        this.xLength = xLength;
        this.yLength = yLength;
    }

    /**
     * Here you should implement a parallel version of the SW alignment algorithm that can support datasets where the
     * size of the S matrix exceeds the available memory.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        // Use two rows for rolling buffer approach to maintain O(yLength) memory
        final int[] row0 = new int[yLength + 1];
        final int[] row1 = new int[yLength + 1];
        final int[][] rows = {row0, row1};

        // Initialize boundary conditions for row 0
        row0[0] = 0;
        for (int j = 1; j <= yLength; j++) {
            row0[j] = getScore(0, 1) * j;
        }

        // Process rows using rolling buffer
        // For each row, we compute cells sequentially (due to left-to-right dependency)
        for (int i = 1; i <= xLength; i++) {
            final int currentRowIdx = i % 2;
            final int prevRowIdx = 1 - currentRowIdx;
            final int[] currRow = rows[currentRowIdx];
            final int[] prevRow = rows[prevRowIdx];

            // Initialize boundary value for current row
            currRow[0] = getScore(1, 0) * i;

            // Process cells in this row sequentially due to dependencies
            for (int j = 1; j <= yLength; j++) {
                // Get characters to compare
                final char XChar = x.charAt(i - 1);
                final char YChar = y.charAt(j - 1);

                // Compute the three possible scores
                final int diagScore = prevRow[j - 1] + getScore(charMap(XChar), charMap(YChar));
                final int topColScore = prevRow[j] + getScore(charMap(XChar), 0);
                final int leftRowScore = currRow[j - 1] + getScore(0, charMap(YChar));

                // Set the maximum score
                currRow[j] = Math.max(diagScore, Math.max(leftRowScore, topColScore));
            }
        }

        // The final answer is in rows[xLength % 2][yLength]
        return rows[xLength % 2][yLength];
    }

}

